-- BD Module — South OC research-import seed
--
-- Imports Amy Dutton's South Orange County referral-source list
-- (Word doc dated 2026-05-15) into bd_accounts. Generated by
-- scripts/bd-south-oc-research-import.py — do not edit by hand;
-- re-run the script with the updated doc instead.
--
-- Behavior:
--   * For each doc row whose (name, city) matches an existing
--     bd_accounts row via the alias table baked into the script,
--     we UPDATE the existing row to fill in address / phone
--     where currently NULL. The existing row's source stays as
--     'manual' or 'trello_import' — we don't overwrite provenance.
--   * For each doc row with no alias match, we INSERT a new
--     bd_accounts row with source='research_import' so the
--     'Prospect' badge surfaces it in the BD portal until Amy
--     logs her first activity against it.
--   * Re-runs are no-ops: the INSERT uses a partial unique index
--     on (org_id, lower(name), lower(coalesce(city,''))) WHERE
--     source='research_import', created in the same migration.
--     The UPDATE statements are idempotent by construction
--     (COALESCE preserves any value already present).
--
-- Production safety: pure additive. No DELETE, no DROP, no
-- destructive change to non-NULL columns on existing rows.
-- Tenant isolation: every INSERT carries org_id = default_org_id()
-- per Phase B locked decisions.
-- Rollback:
--   _rollback/<this-filename>_down.sql clears source='research_import'
--   rows it created, and unsets the address/phone overrides on the
--   aliased rows where the value matches what the up-migration set.

-- ─────────────────────────────────────────────────────────────
-- 1. Idempotency index
-- ─────────────────────────────────────────────────────────────

CREATE UNIQUE INDEX IF NOT EXISTS idx_bd_accounts_research_import_unique
  ON bd_accounts (org_id, lower(name), lower(coalesce(city, '')))
  WHERE source = 'research_import';

