-- ─────────────────────────────────────────────────────────────
-- 4. Hoag named contacts
-- ─────────────────────────────────────────────────────────────
--
-- Five named Hoag contacts from the doc. All land under the
-- Newport Beach Hoag account. The DO block does an exists-check
-- per contact (case-insensitive name) so re-runs do not create
-- duplicates and we do not need to add a unique constraint on
-- bd_account_contacts (which may have legitimate same-name rows
-- across different accounts).

DO $$
DECLARE
  v_org_id      uuid := public.default_org_id();
  v_account_id  uuid;
BEGIN
  -- Resolve the Newport Beach Hoag account by uuid; this is the
  -- strategic-shared row seeded in 20260513140100. Bail silently
  -- if it doesn't exist (e.g. fresh dev DB without the seed).
  SELECT id INTO v_account_id FROM bd_accounts
    WHERE id = '47cbb432-6bfd-4f29-87e4-d52bbcd61378'::uuid
    LIMIT 1;
  IF v_account_id IS NULL THEN
    RAISE NOTICE 'Newport Beach Hoag account not found; skipping contact seed.';
    RETURN;
  END IF;

  IF NOT EXISTS (SELECT 1 FROM bd_account_contacts
                  WHERE account_id = v_account_id
                    AND lower(name) = lower('Amy Robinson')) THEN
    INSERT INTO bd_account_contacts (
      org_id, account_id, name, role, email, phone_office, notes
    ) VALUES (
      v_org_id, v_account_id, 'Amy Robinson', 'social_worker',
      NULL, NULL, 'Hoag Hospice Liaison.'
    );
  END IF;

  IF NOT EXISTS (SELECT 1 FROM bd_account_contacts
                  WHERE account_id = v_account_id
                    AND lower(name) = lower('Arnetta Robinson')) THEN
    INSERT INTO bd_account_contacts (
      org_id, account_id, name, role, email, phone_office, notes
    ) VALUES (
      v_org_id, v_account_id, 'Arnetta Robinson', 'social_worker',
      'arnetta.robinson@hoag.org', '+19492301155', 'Hoag Hospice Liaison.'
    );
  END IF;

  IF NOT EXISTS (SELECT 1 FROM bd_account_contacts
                  WHERE account_id = v_account_id
                    AND lower(name) = lower('Brittany Carrillo')) THEN
    INSERT INTO bd_account_contacts (
      org_id, account_id, name, role, email, phone_office, notes
    ) VALUES (
      v_org_id, v_account_id, 'Brittany Carrillo', 'social_worker',
      NULL, NULL, 'Palliative Care.'
    );
  END IF;

  IF NOT EXISTS (SELECT 1 FROM bd_account_contacts
                  WHERE account_id = v_account_id
                    AND lower(name) = lower('Jenna Gailani, LCSW')) THEN
    INSERT INTO bd_account_contacts (
      org_id, account_id, name, role, email, phone_office, notes
    ) VALUES (
      v_org_id, v_account_id, 'Jenna Gailani, LCSW', 'social_worker',
      NULL, NULL, 'Fudge Family Acute Rehab.'
    );
  END IF;

  IF NOT EXISTS (SELECT 1 FROM bd_account_contacts
                  WHERE account_id = v_account_id
                    AND lower(name) = lower('Madeline Conrado, LCSW')) THEN
    INSERT INTO bd_account_contacts (
      org_id, account_id, name, role, email, phone_office, notes
    ) VALUES (
      v_org_id, v_account_id, 'Madeline Conrado, LCSW', 'social_worker',
      NULL, NULL, 'Neurology.'
    );
  END IF;

END $$;
